what is the difference between this two codes:

code A:

void* print_hello(void *th_id) {
 long tid = (long)th_id;
 printf("Hello World! It's me, thread %ld!\n", tid);
 pthread_exit(NULL);
}
int main (int argc, char *argv[])
{
 pthread_t threads[NUM_THREADS];
 long t;
 for(t=0; t<NUM_THREADS; t++){
 printf(“creating thread %ld\n", t);
 pthread_create(&threads[t], NULL, print_hello, (void *)t);
 }
 exit(0);
}

code B:

void* print_hello(void *th_id) {
 long tid = *(long*)th_id;
 printf("Hello World! It's me, thread %ld!\n", tid);
 free(th_id);
 pthread_exit(NULL);
}
int main (int argc, char *argv[])
{
 pthread_t threads[NUM_THREADS];
 long t;
 for(t=0; t<NUM_THREADS; t++){
 long* th_id = malloc(sizeof(long));
 *th_id = t;
 printf(“creating thread %ld\n", *th_id);
 pthread_create(&threads[t], NULL, print_hello, (void *)th_id);
 }
 exit(0);
}

